// ------ HELPERS ---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
const totalPaid = s => s.payments.reduce((a,p)=>a+p.amount,0);
const balance   = s => s.totalPrice - totalPaid(s);
const calcPT    = cats => Math.round(PRETRIP_CATS.reduce((sum,c)=>sum+((cats[c.id]||0)*c.weight/100),0));
const calcMan   = cats => Math.round(MANEUVER_CATS.reduce((sum,c)=>sum+((cats[c.id]||0)*c.weight/100),0));
const isDMVReady = s => s.progress.preTrip>=75&&s.progress.maneuvers>=75&&s.progress.roadDriving>=75;
const missingDocs = s => Object.entries(s.documents).filter(([,v])=>!v).map(([k])=>DOC_LABELS[k]);
const today = new Date().toISOString().split("T")[0];
const fmtDate = d => d?new Date(d+"T12:00:00").toLocaleDateString("es-US",{month:"short",day:"numeric",year:"numeric"}):"—";
const fmtDateFull = d => d?new Date(d+"T12:00:00").toLocaleDateString("es-US",{weekday:"short",month:"short",day:"numeric"}):"—";
const fmtCur = n => new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",maximumFractionDigits:0}).format(n);
const addBizDays = (ds,days) => {const d=new Date(ds);let a=0;while(a<days){d.setDate(d.getDate()+1);const w=d.getDay();if(w!==0&&w!==3&&w!==6)a++;}return d.toISOString().split("T")[0];};
const avgProg = s => Math.round((s.progress.preTrip+s.progress.maneuvers+s.progress.roadDriving)/3);
const fileToB64 = f => new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res(r.result.split(",")[1]);r.onerror=rej;r.readAsDataURL(f);});
const initPT  = () => {const o={};PRETRIP_CATS.forEach(c=>{o[c.id]=0;});return o;};
const initMan = () => {const o={};MANEUVER_CATS.forEach(c=>{o[c.id]=0;});return o;};
const openWA = (phone, message) => {const clean=phone.replace(/\D/g,"");window.open(`https://wa.me/1${clean}?text=${encodeURIComponent(message)}`,"_blank");};

async function callAI(system, messages) {
  const key = process.env.REACT_APP_ANTHROPIC_API_KEY;
  if(!key) throw new Error("API key no configurada. Ve a Railway → Variables → REACT_APP_ANTHROPIC_API_KEY");
  const res = await fetch("https://api.anthropic.com/v1/messages",{
    method:"POST",
    headers:{"Content-Type":"application/json","x-api-key":key,"anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},
    body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,system,messages})
  });
  if(!res.ok){const e=await res.json().catch(()=>({}));throw new Error(e.error?.message||`Error ${res.status}`);}
  const d=await res.json();
  return d.content?.map(c=>c.text||"").join("")||"";
}

async function ocrExtract(b64,docType,mime){
  try{const t=await callAI("",[{role:"user",content:[{type:"image",source:{type:"base64",media_type:mime,data:b64}},{type:"text",text:EXTRACT_PROMPTS[docType]||EXTRACT_PROMPTS.license}]}]);return JSON.parse(t.replace(/```json|```/g,"").trim());}
  catch{return {};}
}

