function makeS(id,name,phone,ct,tr,status,paid,total,ptV,manV,rd,docs,dmvDate,dmvRes){
  const ptC={};PRETRIP_CATS.forEach((c,i)=>{ptC[c.id]=ptV[i]||0;});
  const manC={};MANEUVER_CATS.forEach((c,i)=>{manC[c.id]=manV[i]||0;});
  return{id,fullName:name,phone,email:`${name.split(" ")[0].toLowerCase()}@email.com`,dob:"1990-01-01",address:"Miami, FL",
    licenseNumber:`FL-${id.toString().padStart(6,"0")}`,licenseExpiry:"2027-12-31",
    contractDate:"2025-01-10",courseStartDate:"2025-01-15",totalPrice:total,courseType:ct,transmission:tr,schedule:"Regular",status,
    payments:paid>0?[{id:1,date:"2025-01-15",amount:paid,method:"Cash",registeredBy:"Admin",note:""}]:[],
    documents:{contract:true,license:true,clp:docs,medicalCard:docs,drugTest:docs&&status!=="Pending Documents",eldt:docs&&status!=="Pending Documents"},
    progress:{pretripCats:ptC,maneuverCats:manC,preTrip:calcPT(ptC),maneuvers:calcMan(manC),roadDriving:rd,history:[]},
    attendance:[],
    dmv:{projectedDate:null,actualDate:dmvDate,time:dmvDate?"08:00":null,location:dmvDate?"DMV Hialeah":null,attempt:1,result:dmvRes,truckAssigned:tr==="Automatic"?"White Truck":"Brown Truck"},
    notes:[],createdAt:"2025-01-10"};
}

