// ------ CALENDAR PAGE ---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
function CalendarPage({students,openS}) {
  const [monthOffset,setMonthOffset]=useState(0);
  const now=new Date();
  const viewDate=new Date(now.getFullYear(),now.getMonth()+monthOffset,1);
  const monthName=viewDate.toLocaleDateString("es-US",{month:"long",year:"numeric"});
  const daysInMonth=new Date(viewDate.getFullYear(),viewDate.getMonth()+1,0).getDate();
  const firstDay=viewDate.getDay();
  const dmvStudents=students.filter(s=>s.dmv.actualDate);

  const getAppts=(day)=>{
    const dateStr=`${viewDate.getFullYear()}-${String(viewDate.getMonth()+1).padStart(2,"0")}-${String(day).padStart(2,"0")}`;
    return dmvStudents.filter(s=>s.dmv.actualDate===dateStr);
  };

  return(
    <div className="pg">
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}>
        <div>
          <h1 style={{fontSize:26,fontWeight:800,color:"#0a1628",fontFamily:"'Inter',sans-serif",letterSpacing:"-.02em"}}>Calendario DMV</h1>
          <p style={{color:"#94a3b8",fontSize:13.5,marginTop:3,textTransform:"capitalize"}}>{monthName}</p>
        </div>
        <div style={{display:"flex",gap:8}}>
          <button className="btn bo" onClick={()=>setMonthOffset(p=>p-1)}>← Anterior</button>
          <button className="btn bo" onClick={()=>setMonthOffset(0)}>Hoy</button>
          <button className="btn bo" onClick={()=>setMonthOffset(p=>p+1)}>Siguiente →</button>
        </div>
      </div>

      <div className="card cp sh" style={{marginBottom:16}}>
        <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:4,marginBottom:8}}>
          {["Dom","Lun","Mar","Mié","Jue","Vie","Sáb"].map((d,i)=>(
            <div key={d} style={{textAlign:"center",fontSize:11,fontWeight:700,color:i===3?"#dc2626":"#94a3b8",letterSpacing:".06em",padding:"4px 0"}}>{d}{i===3&&" →"}</div>
          ))}
        </div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:4}}>
          {Array.from({length:firstDay},(_,i)=><div key={`e${i}`}/>)}
          {Array.from({length:daysInMonth},(_,i)=>{
            const day=i+1;
            const appts=getAppts(day);
            const isToday=today===`${viewDate.getFullYear()}-${String(viewDate.getMonth()+1).padStart(2,"0")}-${String(day).padStart(2,"0")}`;
            const isWed=new Date(viewDate.getFullYear(),viewDate.getMonth(),day).getDay()===3;
            return(
              <div key={day} style={{minHeight:72,borderRadius:8,padding:"6px 8px",background:isToday?"#eff6ff":appts.length>0?"#f0fdf4":isWed?"#fef9f0":"#f8fafc",border:`1px solid ${isToday?"#bfdbfe":appts.length>0?"#bbf7d0":isWed?"#fde68a":"#e2e8f0"}`,fontSize:11}}>
                <div style={{fontWeight:700,color:isToday?"#2563eb":isWed?"#b45309":"#1e293b",marginBottom:4,fontSize:12}}>{day}{isWed&&<span style={{color:"#b45309",fontSize:9,marginLeft:3}}>sin DMV</span>}</div>
                {appts.map(s=>(
                  <div key={s.id} onClick={()=>openS(s)} style={{background:s.transmission==="Automatic"?"#dbeafe":"#fef3c7",color:s.transmission==="Automatic"?"#1e40af":"#92400e",borderRadius:4,padding:"2px 5px",marginBottom:2,cursor:"pointer",fontSize:10,fontWeight:600,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
                    {s.transmission==="Automatic"?"⬜":"🟫"} {s.fullName.split(" ")[0]} {s.dmv.time}
                  </div>
                ))}
              </div>
            );
          })}
        </div>
      </div>

      <div style={{display:"flex",gap:12,flexWrap:"wrap"}}>
        {[["→ Camión Blanco","Automático","#dbeafe","#1e40af"],["🟫 Camión Café","Manual","#fef3c7","#92400e"],["📅 Hoy","","#eff6ff","#2563eb"],["→ Sin DMV","Miércoles","#fef9f0","#b45309"]].map(([icon,label,bg,color])=>(
          <div key={icon} style={{background:bg,border:`1px solid ${color}30`,borderRadius:8,padding:"6px 14px",fontSize:12,fontWeight:600,color}}>{icon} {label}</div>
        ))}
      </div>
    </div>
  );
}

// ------ REPORTS PAGE ------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
function ReportsPage({students}) {
  const totalRevenue=students.reduce((a,s)=>a+totalPaid(s),0);
  const totalPending=students.reduce((a,s)=>a+balance(s),0);
  const byStatus=Object.entries(STATUS_META).map(([k,v])=>({status:v.label,count:students.filter(s=>s.status===k).length,color:v.color})).filter(x=>x.count>0);
  const byClass={A:students.filter(s=>s.courseType==="Class A").length,B:students.filter(s=>s.courseType==="Class B").length,C:students.filter(s=>s.courseType==="Class C Passenger").length};
  const byTrans={Manual:students.filter(s=>s.transmission==="Manual").length,Automatic:students.filter(s=>s.transmission==="Automatic").length};
  const dmvPass=students.filter(s=>s.dmv.result==="Passed").length;
  const dmvFail=students.filter(s=>s.dmv.result==="Failed").length;
  const dmvRate=dmvPass+dmvFail>0?Math.round((dmvPass/(dmvPass+dmvFail))*100):0;

  const exportCSV=()=>{
    const headers=["Nombre","Teléfono","Clase","Transmisión","Estado","Precio","Pagado","Balance","Pre-trip","Maniobras","Manejo","DMV Fecha","DMV Resultado"];
    const rows=students.map(s=>[s.fullName,s.phone,s.courseType,s.transmission,s.status,s.totalPrice,totalPaid(s),balance(s),s.progress.preTrip,s.progress.maneuvers,s.progress.roadDriving,s.dmv.actualDate||"",s.dmv.result||""].join(","));
    const csv=[headers.join(","),...rows].join("\n");
    const blob=new Blob([csv],{type:"text/csv"});
    const url=URL.createObjectURL(blob);
    const a=document.createElement("a");a.href=url;a.download=`FTDSuite_Reporte_${today}.csv`;a.click();
  };

  return(
    <div className="pg">
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}>
        <div>
          <h1 style={{fontSize:26,fontWeight:800,color:"#0a1628",fontFamily:"'Inter',sans-serif",letterSpacing:"-.02em"}}>Reportes y Analytics</h1>
          <p style={{color:"#94a3b8",fontSize:13.5,marginTop:3}}>{students.length} estudiantes en el sistema</p>
        </div>
        <button className="btn bp" onClick={exportCSV}><Ico n="download" s={14}/>Exportar CSV</button>
      </div>

      {/* Financial */}
      <div className="g4" style={{marginBottom:20}}>
        {[["Ingresos Totales",fmtCur(totalRevenue),"#16a34a"],["Balance Pendiente",fmtCur(totalPending),"#b45309"],["Tasa Aprobación DMV",`${dmvRate}%`,"#2563eb"],["Total Estudiantes",students.length,"#7c3aed"]].map(([l,v,c],i)=>(
          <div key={i} className="card cp sh"><div className="stl" style={{marginBottom:8}}>{l}</div><div className="stn" style={{color:c}}>{v}</div></div>
        ))}
      </div>

      <div className="g2" style={{marginBottom:20}}>
        {/* By status */}
        <div className="card cp sh">
          <div className="sec">Estudiantes por Estado</div>
          {byStatus.map(({status,count,color})=>(
            <div key={status} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"9px 0",borderBottom:"1px solid #f1f5f9"}}>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <div style={{width:10,height:10,borderRadius:"50%",background:color,flexShrink:0}}/>
                <span style={{fontSize:13.5,color:"#475569"}}>{status}</span>
              </div>
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <div style={{width:80,height:6,background:"#f1f5f9",borderRadius:3,overflow:"hidden"}}>
                  <div style={{height:"100%",background:color,borderRadius:3,width:`${(count/students.length)*100}%`}}/>
                </div>
                <span style={{fontWeight:700,fontSize:13,fontFamily:"'Inter',sans-serif",minWidth:20,textAlign:"right"}}>{count}</span>
              </div>
            </div>
          ))}
        </div>

        {/* By class and transmission */}
        <div>
          <div className="card cp sh" style={{marginBottom:14}}>
            <div className="sec">Por Clase CDL</div>
            {Object.entries(byClass).filter(([,v])=>v>0).map(([k,v])=>(
              <div key={k} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"8px 0",borderBottom:"1px solid #f1f5f9"}}>
                <span style={{fontSize:13.5,color:"#475569"}}>Class {k}</span>
                <div style={{display:"flex",alignItems:"center",gap:10}}>
                  <div style={{width:80,height:6,background:"#f1f5f9",borderRadius:3,overflow:"hidden"}}>
                    <div style={{height:"100%",background:"#2563eb",borderRadius:3,width:`${(v/students.length)*100}%`}}/>
                  </div>
                  <span style={{fontWeight:700,fontSize:13,fontFamily:"'Inter',sans-serif"}}>{v}</span>
                </div>
              </div>
            ))}
          </div>
          <div className="card cp sh">
            <div className="sec">Por Transmisión</div>
            {Object.entries(byTrans).filter(([,v])=>v>0).map(([k,v])=>(
              <div key={k} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"8px 0",borderBottom:"1px solid #f1f5f9"}}>
                <span style={{fontSize:13.5,color:"#475569"}}>{k==="Automatic"?"🚛 Automático (Camión Blanco)":"🚛 Manual (Camión Café)"}</span>
                <span style={{fontWeight:700,fontSize:13,fontFamily:"'Inter',sans-serif"}}>{v}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Students needing attention */}
      <div className="card cp sh">
        <div className="sec">Estudiantes que Necesitan Atención</div>
        <table className="tbl">
          <thead><tr><th>Estudiante</th><th>Situación</th><th>Detalle</th></tr></thead>
          <tbody>
            {students.filter(s=>balance(s)>0||missingDocs(s).length>0||s.status==="Requires Re-Test").slice(0,10).map(s=>{
              const issues=[];
              if(balance(s)>0)issues.push(`Debe ${fmtCur(balance(s))}`);
              if(missingDocs(s).length>0)issues.push(`${missingDocs(s).length} doc(s) pendiente(s)`);
              if(s.status==="Requires Re-Test")issues.push("Re-test pendiente");
              return(
                <tr key={s.id}>
                  <td style={{fontWeight:600}}>{s.fullName}</td>
                  <td>{issues.map((issue,i)=><span key={i} className="badge" style={{background:"#fef3c7",color:"#92400e",marginRight:4}}>{issue}</span>)}</td>
                  <td style={{fontSize:12,color:"#64748b"}}>{s.courseType} · {s.transmission}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}


// ------ DASHBOARD ---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
function DashPage({students,openS,setWizard,dmvC,totalBal,dmvSoon,activeN}) {
  const grad=students.filter(s=>s.status==="Passed / Graduated").length;
  const retest=students.filter(s=>s.status==="Requires Re-Test").length;
  return(
    <div className="pg">
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:28}}>
        <div><h1 style={{fontSize:26,fontWeight:800,color:"#0a1628",fontFamily:"'Inter',sans-serif",letterSpacing:"-.02em"}}>Dashboard</h1><p style={{color:"#94a3b8",fontSize:13.5,marginTop:3}}>{new Date().toLocaleDateString("es-US",{weekday:"long",year:"numeric",month:"long",day:"numeric"})}</p></div>
        <button className="btn bp blg" onClick={()=>setWizard(true)}><Ico n="plus" s={15}/>Nuevo Estudiante</button>
      </div>
      <div className="g4" style={{marginBottom:20}}>
        {[["Estudiantes Activos",activeN,`${students.length} total`,"#2563eb","👥"],["Balance Pendiente",fmtCur(totalBal),"total por cobrar","#b45309","💰"],["DMV Próximos 7 días",dmvSoon.length,"citas próximas","#0e7490","📅"],["Candidatos DMV",dmvC.length,"listos","#7c3aed","🎯"]].map(([l,v,s,c,icon],i)=>(
          <div key={i} className="card cp sh">
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
              <div><div className="stl" style={{marginBottom:8}}>{l}</div><div className="stn" style={{color:c}}>{v}</div><div style={{fontSize:12,color:"#94a3b8",marginTop:5}}>{s}</div></div>
              <div style={{fontSize:22}}>{icon}</div>
            </div>
          </div>
        ))}
      </div>
      <div className="g3" style={{marginBottom:20}}>
        {[["Graduados",grad,"#16a34a","🎓"],["Re-Tests",retest,"#ea580c","🔄"],["Docs Pendientes",students.filter(s=>missingDocs(s).length>0&&s.status!=="Passed / Graduated").length,"#b45309","📄"]].map(([l,v,c,icon],i)=>(
          <div key={i} className="card cs sh" style={{display:"flex",alignItems:"center",gap:14}}>
            <div style={{fontSize:26}}>{icon}</div>
            <div><div className="stl">{l}</div><div style={{fontSize:22,fontWeight:800,color:c,fontFamily:"'Inter',sans-serif"}}>{v}</div></div>
          </div>
        ))}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20,marginBottom:20}}>
        <div className="card cp sh">
          <div style={{fontWeight:700,fontSize:14,color:"#0a1628",marginBottom:14}}>→ Alertas Urgentes</div>
          {dmvSoon.filter(s=>balance(s)>0).map(s=><div key={s.id} className="al ar" style={{marginBottom:8,cursor:"pointer"}} onClick={()=>openS(s)}><Ico n="warn" s={13}/><span><b>{s.fullName}</b> --- DMV {fmtDate(s.dmv.actualDate)} --- Debe {fmtCur(balance(s))}</span></div>)}
          {students.filter(s=>{const l=s.payments.at(-1)?.date;return l&&(new Date(today)-new Date(l))/86400000>=30&&s.status!=="Passed / Graduated";}).slice(0,3).map(s=><div key={s.id} className="al ay" style={{marginBottom:8}}><Ico n="warn" s={13}/><span><b>{s.fullName}</b> --- Sin pagos por más de 30 días</span></div>)}
          {dmvSoon.filter(s=>balance(s)>0).length===0&&students.filter(s=>{const l=s.payments.at(-1)?.date;return l&&(new Date(today)-new Date(l))/86400000>=30&&s.status!=="Passed / Graduated";}).length===0&&<div style={{color:"#94a3b8",fontSize:13,textAlign:"center",padding:"14px 0"}}>→ Sin alertas activas</div>}
        </div>
        <div className="card cp sh">
          <div style={{fontWeight:700,fontSize:14,color:"#0a1628",marginBottom:14}}>→ Candidatos DMV</div>
          {dmvC.length===0?<div style={{color:"#94a3b8",fontSize:13,textAlign:"center",padding:"14px 0"}}>Sin candidatos</div>:dmvC.slice(0,5).map(s=><div key={s.id} className="al agr" style={{marginBottom:8,cursor:"pointer"}} onClick={()=>openS(s)}><Ico n="check" s={13}/><span><b>{s.fullName}</b> --- {s.courseType} {s.transmission}{missingDocs(s).length>0?` → ${missingDocs(s).length} doc`:""}</span></div>)}
        </div>
      </div>
      <div className="card sh">
        <div style={{padding:"14px 20px",borderBottom:"1px solid #f1f5f9",fontWeight:700,fontSize:14,color:"#0a1628"}}>Estudiantes Recientes</div>
        <table className="tbl">
          <thead><tr><th>Estudiante</th><th>Clase</th><th>Estado</th><th>Progreso</th><th>Balance</th></tr></thead>
          <tbody>{students.slice(0,6).map(s=>{const bal=balance(s);const sm=STATUS_META[s.status]||STATUS_META["Inactive"];const prog=avgProg(s);return(
            <tr key={s.id} onClick={()=>openS(s)}>
              <td><div style={{display:"flex",alignItems:"center",gap:10}}><div className="av" style={{width:34,height:34,fontSize:12}}>{s.fullName.split(" ").map(w=>w[0]).join("").slice(0,2)}</div><div><div style={{fontWeight:600,color:"#0a1628",fontSize:13.5}}>{s.fullName}</div><div style={{fontSize:11.5,color:"#94a3b8"}}>{s.phone}</div></div></div></td>
              <td style={{fontSize:13,color:"#475569"}}>{s.courseType} · {s.transmission}</td>
              <td><span className="badge" style={{background:sm.bg,color:sm.color}}>{sm.label}</span></td>
              <td style={{minWidth:120}}><div style={{fontSize:11,color:"#94a3b8",marginBottom:3}}>{prog}%</div><div className="pt" style={{width:100}}><div className="pf" style={{width:`${prog}%`,background:prog>=75?"#16a34a":"#b45309"}}/></div></td>
              <td style={{fontWeight:700,color:bal>0?"#b45309":"#16a34a",fontFamily:"'Inter',sans-serif"}}>{fmtCur(bal)}</td>
            </tr>
          );})}</tbody>
        </table>
      </div>
    </div>
  );
}

// ------ STUDENTS PAGE ---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
function StudentsPage({students,openS,setWizard,onBulkImport}) {
  const [search,setSearch]=useState("");const [stF,setStF]=useState("all");const [clF,setClF]=useState("all");const [trF,setTrF]=useState("all");const [page,setPage]=useState(1);const PER=20;
  const filtered=useMemo(()=>students.filter(s=>{const q=search.toLowerCase();return(!q||s.fullName.toLowerCase().includes(q)||s.phone.includes(q)||s.licenseNumber.toLowerCase().includes(q))&&(stF==="all"||s.status===stF)&&(clF==="all"||s.courseType===clF)&&(trF==="all"||s.transmission===trF);}),[students,search,stF,clF,trF]);
  const pages=Math.ceil(filtered.length/PER);const paged=filtered.slice((page-1)*PER,page*PER);const reset=()=>setPage(1);
  return(
    <div className="pg">
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
        <div><h1 style={{fontSize:26,fontWeight:800,color:"#0a1628",fontFamily:"'Inter',sans-serif",letterSpacing:"-.02em"}}>Estudiantes</h1><p style={{color:"#94a3b8",fontSize:13.5,marginTop:3}}>{filtered.length} de {students.length} registros</p></div>
        <button className="btn bp blg" onClick={()=>setWizard(true)}><Ico n="plus" s={15}/>Nuevo Estudiante</button>
      </div>
      <div className="card cs sh" style={{marginBottom:12}}>
        <div style={{display:"flex",gap:10,flexWrap:"wrap",alignItems:"center"}}>
          <div className="sw" style={{flex:1,minWidth:180}}><Ico n="search" s={14}/><input className="inp si" placeholder="Nombre, teléfono, licencia..." value={search} onChange={e=>{setSearch(e.target.value);reset();}}/></div>
          <select className="sel" style={{width:175}} value={stF} onChange={e=>{setStF(e.target.value);reset();}}><option value="all">Todos los estados</option>{Object.entries(STATUS_META).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}</select>
          <select className="sel" style={{width:120}} value={clF} onChange={e=>{setClF(e.target.value);reset();}}><option value="all">Todas clases</option><option>Class A</option><option>Class B</option><option>Class C Passenger</option></select>
          <select className="sel" style={{width:130}} value={trF} onChange={e=>{setTrF(e.target.value);reset();}}><option value="all">Transmisión</option><option>Manual</option><option>Automatic</option></select>
          {(search||stF!=="all"||clF!=="all"||trF!=="all")&&<button className="btn bo bsm" onClick={()=>{setSearch("");setStF("all");setClF("all");setTrF("all");reset();}}>→ Limpiar</button>}
        </div>
      </div>
      <div className="card sh" style={{marginBottom:12}}>
        <table className="tbl">
          <thead><tr><th>Estudiante</th><th>Clase</th><th>Estado</th><th>Pre-trip</th><th>Maniobras</th><th>Manejo</th><th>Balance</th><th>DMV</th><th>Docs</th></tr></thead>
          <tbody>{paged.length===0?<tr><td colSpan={9} style={{textAlign:"center",color:"#94a3b8",padding:"32px"}}>Sin resultados</td></tr>:paged.map(s=>{const bal=balance(s);const sm=STATUS_META[s.status]||STATUS_META["Inactive"];const md=missingDocs(s);return(
            <tr key={s.id} onClick={()=>openS(s)}>
              <td><div style={{display:"flex",alignItems:"center",gap:10}}><div className="av" style={{width:36,height:36,fontSize:12}}>{s.fullName.split(" ").map(w=>w[0]).join("").slice(0,2)}</div><div><div style={{fontWeight:600,color:"#0a1628",fontSize:13.5}}>{s.fullName}</div><div style={{fontSize:11.5,color:"#94a3b8"}}>{s.phone}</div></div></div></td>
              <td style={{fontSize:13,color:"#475569"}}>{s.courseType}<br/><span style={{fontSize:11}}>{s.transmission}</span></td>
              <td><span className="badge" style={{background:sm.bg,color:sm.color}}>{sm.label}</span></td>
              {[s.progress.preTrip,s.progress.maneuvers,s.progress.roadDriving].map((v,i)=><td key={i}><div style={{fontSize:12,fontWeight:700,color:v>=75?"#16a34a":"#b45309",marginBottom:3}}>{v}%</div><div className="pt" style={{width:70}}><div className="pf" style={{width:`${v}%`,background:v>=75?"#16a34a":"#b45309"}}/></div></td>)}
              <td style={{fontWeight:700,color:bal>0?"#b45309":"#16a34a",fontFamily:"'Inter',sans-serif",fontSize:13}}>{fmtCur(bal)}</td>
              <td style={{fontSize:12,color:"#64748b"}}>{s.dmv.actualDate?fmtDate(s.dmv.actualDate):"—"}</td>
              <td>{md.length===0?<span style={{color:"#16a34a",fontSize:13}}>✓</span>:<span style={{color:"#b45309",fontSize:12,fontWeight:600}}>→ {md.length}</span>}</td>
            </tr>
          );})}</tbody>
        </table>
      </div>
      {pages>1&&<div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div style={{fontSize:13,color:"#94a3b8"}}>Mostrando {(page-1)*PER+1}{Math.min(page*PER,filtered.length)} de {filtered.length}</div>
        <div style={{display:"flex",gap:6}}>
          <button className="btn bo bsm" disabled={page===1} onClick={()=>setPage(p=>p-1)}>→ Ant.</button>
          {Array.from({length:Math.min(pages,7)},(_,i)=>{let pg=i+1;if(pages>7&&page>4){pg=page-3+i;if(pg>pages)return null;}return<button key={pg} className={`btn bsm ${pg===page?"bp":"bo"}`} onClick={()=>setPage(pg)}>{pg}</button>;}).filter(Boolean)}
          <button className="btn bo bsm" disabled={page===pages} onClick={()=>setPage(p=>p+1)}>Sig. →</button>
        </div>
      </div>}
    </div>
  );
}

// ------ STUDENT DETAIL ------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
function DetailPage({s,updateS,goBack,sTab,setSTab,perms,addToast}) {
  const bal=balance(s);const md=missingDocs(s);const cand=isDMVReady(s);const sm=STATUS_META[s.status]||STATUS_META["Inactive"];
  const [editN,setEditN]=useState(false);const [nV,setNV]=useState(s.fullName);
  const saveN=()=>{if(nV.trim())updateS({...s,fullName:nV.trim()});setEditN(false);};
  const tabs=[["overview","Resumen"],["progress","Progreso"],["documents","Documentos"],["dmv","DMV"],["attendance","Asistencia"],["notes","Notas"],...(perms.canPay?[["payments","Pagos"]]:[] )];
  return(
    <div className="pg">
      <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:20}}>
        <button className="btn bo bsm" onClick={goBack}><Ico n="back" s={13}/>Volver</button>
        <div style={{flex:1,display:"flex",alignItems:"center",gap:14}}>
          <div className="av" style={{width:48,height:48,fontSize:17}}>{s.fullName.split(" ").map(w=>w[0]).join("").slice(0,2)}</div>
          <div>
            {editN?(<div style={{display:"flex",alignItems:"center",gap:8}}>
              <input className="inp" style={{fontSize:17,fontWeight:700,padding:"6px 12px",width:280}} value={nV} onChange={e=>setNV(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")saveN();if(e.key==="Escape")setEditN(false);}} autoFocus/>
              <button className="btn bp bsm" onClick={saveN}>→</button>
              <button className="btn bo bsm" onClick={()=>setEditN(false)}>→</button>
            </div>):(<div style={{display:"flex",alignItems:"center",gap:8}}>
              <h1 style={{fontSize:22,fontWeight:800,color:"#0a1628",fontFamily:"'Inter',sans-serif"}}>{s.fullName}</h1>
              {perms.canUsers&&<button className="btn bgh" style={{padding:"5px 8px",borderRadius:7}} onClick={()=>{setNV(s.fullName);setEditN(true);}}><Ico n="edit" s={14}/></button>}
            </div>)}
            <div style={{display:"flex",gap:8,alignItems:"center",marginTop:4}}>
              <span className="badge" style={{background:sm.bg,color:sm.color}}>{sm.label}</span>
              <span style={{fontSize:12.5,color:"#94a3b8"}}>{s.courseType} · {s.transmission} · {s.schedule}</span>
            </div>
          </div>
        </div>
        <div style={{display:"flex",gap:8,alignItems:"center"}}>
          {s.phone&&perms.canMessages&&<button className="wa-btn" onClick={()=>openWA(s.phone,WA_TEMPLATES.payment_reminder(s,bal))}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
            WhatsApp
          </button>}
          <div style={{textAlign:"right",background:bal>0?"#fef3c7":"#dcfce7",padding:"10px 16px",borderRadius:10,border:`1px solid ${bal>0?"#fde68a":"#bbf7d0"}`}}>
            <div style={{fontSize:20,fontWeight:800,color:bal>0?"#b45309":"#16a34a",fontFamily:"'Inter',sans-serif"}}>{fmtCur(bal)}</div>
            <div style={{fontSize:11,color:"#94a3b8"}}>balance</div>
          </div>
        </div>
      </div>
      {bal>0&&s.dmv.actualDate&&(new Date(s.dmv.actualDate)-new Date(today))/86400000<=7&&<div className="al ar" style={{marginBottom:10}}><Ico n="warn" s={14}/><span><b>ALERTA:</b> DMV {fmtDate(s.dmv.actualDate)} con balance {fmtCur(bal)}.</span></div>}
      {md.length>0&&cand&&<div className="al ay" style={{marginBottom:10}}><Ico n="warn" s={13}/><span><b>Docs faltantes:</b> {md.join(", ")}</span></div>}
      {cand&&md.length===0&&bal===0&&!["DMV Scheduled","Passed / Graduated"].includes(s.status)&&<div className="al agr" style={{marginBottom:10}}><Ico n="check" s={13}/><span><b>Listo para DMV.</b> Sugerido: {fmtDate(addBizDays(today,13))}</span></div>}
      <div className="tabs" style={{marginBottom:18,width:"fit-content"}}>
        {tabs.map(([id,lbl])=><button key={id} className={`tab${sTab===id?" on":""}`} onClick={()=>setSTab(id)}>{lbl}</button>)}
      </div>
      {sTab==="overview"   && <OverviewTab s={s}/>}
      {sTab==="progress"   && <ProgressTab s={s} updateS={updateS} canEdit={perms.canProg}/>}
      {sTab==="documents"  && <DocsTab s={s} updateS={updateS}/>}
      {sTab==="dmv"        && <DmvTab s={s} updateS={updateS} addToast={addToast} perms={perms}/>}
      {sTab==="attendance" && <AttTab s={s} updateS={updateS}/>}
      {sTab==="notes"      && <NotesTab s={s} updateS={updateS}/>}
      {sTab==="payments"   && perms.canPay && <PayTab s={s} updateS={updateS} addToast={addToast} perms={perms}/>}
    </div>
  );
}

function OverviewTab({s}) {
  const bal=balance(s);
  return(<div className="g2">
    {[{title:"👤 Datos Personales",rows:[["Nombre Completo",s.fullName||"—"],["Teléfono",s.phone||"—"],["Email",s.email||"—"],["Fecha Nac.",fmtDate(s.dob)],["Dirección",s.address||"—"]]},{title:"📋 Curso",rows:[["Clase CDL",s.courseType],["Transmisión",s.transmission],["Horario",s.schedule],["Inicio",fmtDate(s.courseStartDate)],["Precio",fmtCur(s.totalPrice)],["Pagado",fmtCur(totalPaid(s))],["Balance",fmtCur(bal)]]},{title:"🪪 Licencia",rows:[["Número",s.licenseNumber||"—"],["Vence",fmtDate(s.licenseExpiry)]]}].map((sec,i)=>(
      <div key={i} className="card cp sh">
        <div className="sec">{sec.title}</div>
        {sec.rows.map(([k,v])=>(<div key={k} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:"1px solid #f1f5f9",fontSize:13.5}}>
          <span style={{color:"#64748b",fontWeight:500}}>{k}</span>
          <span style={{fontWeight:k==="Nombre Completo"?800:600,color:k==="Balance"?(bal>0?"#b45309":"#16a34a"):k==="Nombre Completo"?"#0a1628":"#1e293b",maxWidth:"58%",textAlign:"right"}}>{v}</span>
        </div>))}
      </div>
    ))}
    <div className="card cp sh">
      <div className="sec">📈 Progreso General</div>
      {[["Pre-trip",s.progress.preTrip],["Maniobras",s.progress.maneuvers],["Manejo en Ruta",s.progress.roadDriving]].map(([k,v])=>(<div key={k} style={{marginBottom:14}}>
        <div style={{display:"flex",justifyContent:"space-between",fontSize:13.5,marginBottom:6}}><span style={{color:"#475569",fontWeight:500}}>{k}</span><span style={{fontWeight:700,color:v>=75?"#16a34a":"#b45309"}}>{v}%</span></div>
        <div className="pt ptlg"><div className="pf" style={{width:`${v}%`,background:v>=75?"#16a34a":"#b45309"}}/></div>
      </div>))}
    </div>
  </div>);
}

function ProgressTab({s,updateS,canEdit}) {
  const [editing,setEditing]=useState(false);
  const [ptV,setPtV]=useState({...s.progress.pretripCats});
  const [manV,setManV]=useState({...s.progress.maneuverCats});
  const [rdV,setRdV]=useState(s.progress.roadDriving);
  const ppT=calcPT(ptV);const ppM=calcMan(manV);
  const save=()=>{updateS({...s,progress:{...s.progress,pretripCats:{...ptV},maneuverCats:{...manV},roadDriving:rdV,history:[...s.progress.history,{date:today,by:"Admin"}]}});setEditing(false);};
  return(<div>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
      <h2 style={{fontSize:18,fontWeight:800,color:"#0a1628",fontFamily:"'Inter',sans-serif"}}>Progreso</h2>
      {canEdit&&(!editing?<button className="btn bo" onClick={()=>setEditing(true)}><Ico n="edit" s={14}/>Actualizar</button>:<div style={{display:"flex",gap:8}}><button className="btn bo" onClick={()=>setEditing(false)}>Cancelar</button><button className="btn bp" onClick={save}>Guardar</button></div>)}
    </div>
    {[{title:"Pre-Trip Inspection",cats:PRETRIP_CATS,vals:ptV,setVals:setPtV,score:editing?ppT:s.progress.preTrip},{title:"Maniobras / Backing",cats:MANEUVER_CATS,vals:manV,setVals:setManV,score:editing?ppM:s.progress.maneuvers}].map(({title,cats,vals,setVals,score})=>(
      <div key={title} className="card cp sh" style={{marginBottom:14}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}><div style={{fontWeight:700,fontSize:16,color:"#0a1628"}}>{title}</div><div style={{fontFamily:"'Inter',sans-serif",fontSize:26,fontWeight:900,color:score>=75?"#16a34a":"#b45309"}}>{score}%</div></div>
        <div className="pt ptlg" style={{marginBottom:16}}><div className="pf" style={{width:`${score}%`,background:score>=75?"#16a34a":"#b45309"}}/></div>
        {cats.map(cat=>{const v=editing?vals[cat.id]||0:s.progress[title.includes("Pre")?"pretripCats":"maneuverCats"][cat.id]||0;return(
          <div key={cat.id} className="cat-row">
            <div style={{width:175,fontSize:13,fontWeight:600,color:"#1e293b",flexShrink:0}}>{cat.label}</div>
            <div style={{fontSize:11,color:"#94a3b8",width:34,flexShrink:0,textAlign:"right",fontWeight:700}}>{cat.weight}%</div>
            {editing?<input type="range" min="0" max="100" value={vals[cat.id]||0} onChange={e=>setVals(p=>({...p,[cat.id]:+e.target.value}))} className="cat-sl"/>:<div className="pt" style={{flex:1}}><div className="pf" style={{width:`${v}%`,background:v>=75?"#16a34a":"#b45309"}}/></div>}
            {editing?<input type="number" min="0" max="100" value={vals[cat.id]||0} onChange={e=>setVals(p=>({...p,[cat.id]:Math.min(100,Math.max(0,+e.target.value))}))} style={{width:56,background:"#f8fafc",border:"1.5px solid #e2e8f0",borderRadius:6,padding:"4px 8px",fontSize:13,textAlign:"center",fontFamily:"inherit",color:"#1e293b"}}/>:<span style={{fontSize:13,fontWeight:700,color:v>=75?"#16a34a":"#b45309",minWidth:38,textAlign:"right"}}>{v}%</span>}
          </div>
        );})}
      </div>
    ))}
    <div className="card cp sh" style={{marginBottom:14}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}><div style={{fontWeight:700,fontSize:16,color:"#0a1628"}}>Manejo en Ruta</div><div style={{fontFamily:"'Inter',sans-serif",fontSize:26,fontWeight:900,color:(editing?rdV:s.progress.roadDriving)>=75?"#16a34a":"#b45309"}}>{editing?rdV:s.progress.roadDriving}%</div></div>
      <div className="pt ptlg" style={{marginBottom:10}}><div className="pf" style={{width:`${editing?rdV:s.progress.roadDriving}%`,background:(editing?rdV:s.progress.roadDriving)>=75?"#16a34a":"#b45309"}}/></div>
      {editing&&<input type="range" min="0" max="100" value={rdV} onChange={e=>setRdV(+e.target.value)} style={{width:"100%",accentColor:"#2563eb",marginTop:4}}/>}
    </div>
    {isDMVReady(s)&&<div className="al agr"><Ico n="check" s={14}/><span><b>Candidato DMV.</b> Los tres indicadores están en 75%+.</span></div>}
  </div>);
}

